import{_ as t,o as a,c as r,S as o}from"./chunks/framework.DZlzLDBr.js";const c=JSON.parse('{"title":"Gatekeeper","description":"","frontmatter":{},"headers":[],"relativePath":"Gatekeeper.md","filePath":"Gatekeeper.md","lastUpdated":null}'),d={name:"Gatekeeper.md"};function n(s,e,i,l,p,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="gatekeeper" tabindex="-1">Gatekeeper <a class="header-anchor" href="#gatekeeper" aria-label="Permalink to &quot;Gatekeeper&quot;">​</a></h1><p>Last modified: 04/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Gatekeeper is a stricter reminder mode that opens a due-card review popup.</p><p>It is designed for times when you want study to happen before you continue with normal work.</p><p>For gentler nudges, see <a href="./Reminders">Reminders</a>.</p><h2 id="activation" tabindex="-1">Activation <a class="header-anchor" href="#activation" aria-label="Permalink to &quot;Activation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Enable gatekeeper popups</td><td>Enables recurring Gatekeeper rounds.</td></tr><tr><td>Enable gatekeeper on launch</td><td>Runs one Gatekeeper round after Obsidian starts.</td></tr></tbody></table><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Gatekeeper frequency</td><td>Time between Gatekeeper rounds, in minutes.</td></tr><tr><td>Number of due questions</td><td>How many due cards to include per round.</td></tr><tr><td>Gatekeeper scoping</td><td>Choose whether Gatekeeper blocks only the current tab or the full workspace.</td></tr><tr><td>Pause Gatekeeper while studying</td><td>Pauses countdown in Sprout study tabs and resumes after you leave.</td></tr></tbody></table><h2 id="bypass" tabindex="-1">Bypass <a class="header-anchor" href="#bypass" aria-label="Permalink to &quot;Bypass&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Enable gatekeeper bypass</td><td>Allows closing/skipping a round before all shown cards are completed.</td></tr><tr><td>Enable bypass warning</td><td>Shows a confirmation prompt before bypassing.</td></tr></tbody></table><p>If fewer due cards are available than requested, Gatekeeper shows all available due cards. If no cards are due, the round is skipped.</p><h2 id="behavior-notes" tabindex="-1">Behavior notes <a class="header-anchor" href="#behavior-notes" aria-label="Permalink to &quot;Behavior notes&quot;">​</a></h2><ul><li>Gatekeeper on launch runs on app start, not on settings toggles.</li><li>Gatekeeper rounds use your current due-card state from the scheduler.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Reminders">Reminders</a></li><li><a href="./Study-Sessions">Study-Sessions</a></li><li><a href="./Grading">Grading</a></li><li><a href="./Settings">Settings</a></li></ul>',17)])])}const b=t(d,[["render",n]]);export{c as __pageData,b as default};
